// ── CONFIGURE THESE FOUR VALUES ──────────────────────────
const CONFIG = {
  productUuid: 'YOUR_PRODUCT_UUID',
  clientUuid:  'YOUR_WORKSPACE_UUID',
  productName: 'Your Product Name',
  filePrefix:  'attributes_completed_'
};
// ──────────────────────────────────────────────────────────
return [{ json: CONFIG }];

// Merge trigger + config so downstream nodes have both
const config = $node['Config'].json;
return [{ json: config }];

// Find the newest attachment matching the filename prefix.
// Skip if already processed (UUID stored in workflow static data).

const prefix      = $node['Config'].json.filePrefix.toLowerCase();
const attachments = $input.first().json.response?.grid ?? [];

const candidates = attachments
  .filter(a => (a.name ?? '').toLowerCase().startsWith(prefix) &&
               (a.name ?? '').toLowerCase().endsWith('.xlsx'))
  .sort((a, b) => new Date(b.created ?? 0) - new Date(a.created ?? 0));

if (!candidates.length) {
  return [{ json: { skip: true, reason: 'No matching attachment found.' } }];
}

const latest     = candidates[0];
const staticData = $getWorkflowStaticData('global');

if (latest.uuid === staticData.lastProcessedUuid) {
  return [{ json: { skip: true, reason: `Already processed: ${latest.name}` } }];
}

staticData.lastProcessedUuid = latest.uuid;
staticData.lastProcessedAt   = new Date().toISOString();

return [{ json: { skip: false, blobId: latest.blobId, name: latest.name } }];

// Build the attributes array from the spreadsheet rows.
// Each row must have: attribute_key | attribute_value
// This REPLACES all existing product attributes — nothing is preserved.

const rows = $input.all().map(i => i.json);
const attributes = [];

for (const row of rows) {
  const key   = String(row['attribute_key']   ?? '').trim();
  const value = String(row['attribute_value'] ?? '').trim();
  if (!key) continue;
  attributes.push({ name: key, value });
}

if (!attributes.length) {
  throw new Error('Spreadsheet has no valid rows. Check column headers: attribute_key | attribute_value');
}

const config = $node['Config'].json;
return [{ json: {
  uuid:       config.productUuid,
  name:       config.productName,
  attributes
} }];
